// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef, useMemo } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';

// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}

function useComponent(props: Props) {
  // Map weather conditions to icons/emojis
  const getWeatherIcon = useCallback((condition: string): string => {
    const normalized = condition.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️';
    if (normalized.includes('rainy') || normalized.includes('rain')) return '🌧️';
    if (normalized.includes('snow')) return '❄️';
    if (normalized.includes('thunderstorm') || normalized.includes('storm')) return '⛈️';
    if (normalized.includes('wind')) return '💨';
    if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
    return '🌤️'; // default
  }, []);

  // Format temperature with unit
  const displayUnit = props.unit || 'C';
  const formattedTemp = useMemo(() => {
    return `${Math.round(props.temperature)}°${displayUnit}`;
  }, [props.temperature, displayUnit]);

  // Get weather icon for current condition
  const currentIcon = useMemo(() => {
    return getWeatherIcon(props.condition);
  }, [props.condition, getWeatherIcon]);

  return {
    formattedTemp,
    currentIcon,
    getWeatherIcon,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* Main Weather Card */}
        <Card shadow="md" padding={32} radius="lg">
          <Stack gap={24}>
            {/* Header with city name */}
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">{props.city}</Heading>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{props.condition}</Text>
            </Stack>

            {/* Temperature Section */}
            <Stack align="center" gap={16}>
              <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600, #0284c7)" align="center">
                {state.formattedTemp}
              </Text>
              <Text size="3xl" align="center">
                {state.currentIcon}
              </Text>
            </Stack>

            <Divider margin={16} />

            {/* Humidity and Wind Speed */}
            <Row gap={24} align="center" justify="center">
              <Stack align="center" gap={8}>
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-500, #0ea5e9)" />
                <Stack align="center" gap={2}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
                  <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{props.humidity}%</Text>
                </Stack>
              </Stack>

              <Stack align="center" gap={8}>
                <Icon name="wind" size={24} color="var(--ggui-color-warning-500, #f59e0b)" />
                <Stack align="center" gap={2}>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
                  <Text size="lg" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{props.windSpeed} m/s</Text>
                </Stack>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        {props.forecast && props.forecast.length > 0 && (
          <Card shadow="sm" padding={20} radius="lg">
            <Stack gap={16}>
              <Heading level={4} color="var(--ggui-color-onSurface, #18181b)">5-Day Forecast</Heading>
              <Row gap={12} align="start" justify="between" wrap>
                {props.forecast.map((day, index) => {
                  const dayIcon = day.icon ? state.getWeatherIcon(day.icon) : '🌤️';
                  return (
                    <Card key={index} shadow="none" padding={16} radius="md" border={true} style={{ flex: '1 1 calc(20% - 10px)', minWidth: '80px' }}>
                      <Stack align="center" gap={8}>
                        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">{day.day || `Day ${index + 1}`}</Text>
                        <Text size="2xl" align="center">{dayIcon}</Text>
                        <Stack direction="horizontal" gap={4} align="center" justify="center">
                          <Text size="sm" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">{Math.round(day.high || 0)}°{props.unit || 'C'}</Text>
                          <Text size="sm" color="var(--ggui-color-onSurfaceVariant, #52525b)">{Math.round(day.low || 0)}°{props.unit || 'C'}</Text>
                        </Stack>
                      </Stack>
                    </Card>
                  );
                })}
              </Row>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };

function useComponent(props: Props) {
  // State
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Get onSubmit callback from props (with fallback)
  const onSubmitCallback = useCallback((payload: ActionSubmitPayload) => {
    if (typeof (props as any).onSubmit === 'function') {
      (props as any).onSubmit(payload);
    }
  }, [props]);

  // Validate email format
  const isValidEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  // Validate name field (inline on every keystroke)
  const validateName = useCallback((value: string): void => {
    if (!value.trim()) {
      setNameError('Name is required');
    } else {
      setNameError('');
    }
  }, []);

  // Validate email field (inline on every keystroke)
  const validateEmail = useCallback((value: string): void => {
    if (!value.trim()) {
      setEmailError('Email is required');
    } else if (!isValidEmail(value)) {
      setEmailError('Please enter a valid email address');
    } else {
      setEmailError('');
    }
  }, [isValidEmail]);

  // Validate current step (for form submission, not inline)
  const isStep1Valid = useCallback((): boolean => {
    return name.trim() !== '' && email.trim() !== '' && isValidEmail(email);
  }, [name, email, isValidEmail]);

  // Validate step 2
  const isStep2Valid = useCallback((): boolean => {
    return satisfaction !== '';
  }, [satisfaction]);

  // Handle Next button
  const handleNext = useCallback((): void => {
    if (currentStep === 1 && !isStep1Valid()) return;
    if (currentStep === 2 && !isStep2Valid()) return;
    if (currentStep < 5) {
      setCurrentStep(currentStep + 1);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  // Handle Back button
  const handleBack = useCallback((): void => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  // Handle feature toggle
  const handleFeatureToggle = useCallback((feature: string): void => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  }, []);

  // Handle Submit
  const handleSubmit = useCallback((): void => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: parseInt(satisfaction, 10),
      features,
      comments: comments.trim(),
    };
    onSubmitCallback(payload);
  }, [name, email, satisfaction, features, comments, onSubmitCallback]);

  return { currentStep, setCurrentStep, name, setName, email, setEmail, nameError, validateName, validateEmail, emailError, satisfaction, setSatisfaction, features, handleFeatureToggle, comments, setComments, handleNext, handleBack, handleSubmit, isStep1Valid, isStep2Valid };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  // Calculate progress percentage
  const progressValue = (state.currentStep / 5) * 100;

  // Radio options for satisfaction (1-5 scale)
  // Radio options for satisfaction (1-5 scale) with null guard
  const satisfactionOptions = (props.satisfactionLabels || []).map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} - ${label}`,
  }));

  return (
    <Container maxWidth="md" padding={24}>
      <Stack gap={24}>
        {/* Header */}
        <Stack gap={8}>
          <Heading level={2}>Multi-Step Survey</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
            Step {state.currentStep} of 5
          </Text>
          <Progress value={progressValue} max={100} size="md" />
        </Stack>

        {/* Step 1: Personal Information */}
        {state.currentStep === 1 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Stack gap={4}>
                <Heading level={3}>Your Information</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please provide your basic details
                </Text>
              </Stack>
              <Input
                label="Full Name"
                placeholder="John Doe"
                value={state.name}
                onChange={(value) => { state.setName(value); state.validateName(value); }}
                error={state.nameError}
                required
              />
              <Input
                label="Email Address"
                type="email"
                placeholder="john@example.com"
                value={state.email}
                onChange={(value) => { state.setEmail(value); state.validateEmail(value); }}
                error={state.emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {state.currentStep === 2 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Stack gap={4}>
                <Heading level={3}>Satisfaction Rating</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  How satisfied are you with our service?
                </Text>
              </Stack>
              <RadioGroup
                label="Rate your satisfaction"
                value={state.satisfaction}
                onChange={state.setSatisfaction}
                options={satisfactionOptions}
                direction="vertical"
              />
            </Stack>
          </Card>
        )}

         {/* Step 3: Feature Interests */}
         {state.currentStep === 3 && (
           <Card shadow="md" padding={24} radius="lg">
             <Stack gap={16}>
               <Stack gap={4}>
                 <Heading level={3}>Features of Interest</Heading>
                 <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                   Which features interest you most?
                 </Text>
               </Stack>
               <Stack gap={12}>
                 {(props.featureOptions || []).map((feature) => (
                   <Checkbox
                     key={feature}
                     label={feature}
                     checked={state.features.includes(feature)}
                     onChange={() => state.handleFeatureToggle(feature)}
                   />
                 ))}
               </Stack>
             </Stack>
           </Card>
         )}

        {/* Step 4: Comments */}
        {state.currentStep === 4 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Stack gap={4}>
                <Heading level={3}>Additional Comments</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Any additional feedback (optional)?
                </Text>
              </Stack>
              <TextArea
                label="Comments"
                placeholder="Share your thoughts..."
                value={state.comments}
                onChange={state.setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Step 5: Final Review */}
        {state.currentStep === 5 && (
          <Card shadow="md" padding={24} radius="lg">
            <Stack gap={16}>
              <Stack gap={4}>
                <Heading level={3}>Review Your Answers</Heading>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Please review your information before submitting
                </Text>
              </Stack>
              <Divider />
              <Stack gap={16}>
                {/* Name */}
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Full Name</Text>
                  <Text variant="body">{state.name || '(empty)'}</Text>
                </Box>
                {/* Email */}
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email Address</Text>
                  <Text variant="body">{state.email || '(empty)'}</Text>
                </Box>
                {/* Satisfaction */}
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction Rating</Text>
                  <Text variant="body">
                    {state.satisfaction && satisfactionOptions.find(o => o.value === state.satisfaction)?.label || '(not selected)'}
                  </Text>
                </Box>
                {/* Features */}
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features of Interest</Text>
                  {state.features.length > 0 ? (
                    <Stack gap={6}>
                      {state.features.map((feature) => (
                        <Badge key={feature} variant="primary" size="sm">{feature}</Badge>
                      ))}
                    </Stack>
                  ) : (
                    <Text variant="body">(none selected)</Text>
                  )}
                </Box>
                {/* Comments */}
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Additional Comments</Text>
                  <Text variant="body">{state.comments || '(empty)'}</Text>
                </Box>
              </Stack>
            </Stack>
          </Card>
        )}
        {/* Navigation Buttons */}
        <Stack direction="horizontal" gap={12} justify="between" align="center">
          <Button
            variant="outline"
            onClick={state.handleBack}
            disabled={state.currentStep === 1}
          >
            Back
          </Button>
          <Stack direction="horizontal" gap={12}>
            {state.currentStep < 5 && (
              <Button
                variant="primary"
                onClick={state.handleNext}
                disabled={
                  (state.currentStep === 1 && !state.isStep1Valid()) ||
                  (state.currentStep === 2 && !state.isStep2Valid())
                }
              >
                Next
              </Button>
            )}
            {state.currentStep === 5 && (
              <Button variant="primary" onClick={state.handleSubmit}>
                Submit Survey
              </Button>
            )}
            {state.currentStep === 4 && (
              <Button variant="primary" onClick={state.handleNext}>
                Review
              </Button>
            )}
          </Stack>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
import React, { useState, useCallback, useRef } from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';


// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };

// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };

function useComponent(props: Props) {
  // Actions — fire-and-forget to agent
  const taskUpdate = (payload: ActionTaskUpdatePayload) => {
    window.dispatchEvent(new CustomEvent('ggui:action', { detail: { action: 'taskUpdate', payload } }));
  };

  // Local state for tasks (merged from props + stream updates)
  const [tasks, setTasks] = useState(props.tasks || []);
  const propsTasksRef = useRef(props.tasks || []);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const [addingColumnId, setAddingColumnId] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync props.tasks to state when props change (reconciliation)
  React.useEffect(() => {
    propsTasksRef.current = props.tasks || [];
    setTasks(props.tasks || []);
  }, [props.tasks]);

  // Listen for real-time stream updates via ggui:agent-data events
  React.useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;
      if (data && data.stream === 'taskChanged' && data.event) {
        const taskChangeEvent = data.event as StreamTaskChanged;
        if (taskChangeEvent.action === 'create' && taskChangeEvent.task) {
          setTasks((prev) => {
            const exists = prev.some((t) => t.id === taskChangeEvent.task!.id);
            return exists ? prev : [...prev, taskChangeEvent.task!];
          });
        } else if (taskChangeEvent.action === 'move' && taskChangeEvent.task) {
          setTasks((prev) => prev.map((t) => (t.id === taskChangeEvent.task!.id ? taskChangeEvent.task! : t)));
        } else if (taskChangeEvent.action === 'edit' && taskChangeEvent.task) {
          setTasks((prev) => prev.map((t) => (t.id === taskChangeEvent.task!.id ? { ...t, ...taskChangeEvent.task! } : t)));
        } else if (taskChangeEvent.action === 'delete' && taskChangeEvent.task?.id) {
          setTasks((prev) => {
            const filtered = prev.filter((t) => t.id !== taskChangeEvent.task!.id);
             if (editingTaskId === taskChangeEvent.task!.id) {
               setEditingTaskId(null);
               setEditingTitle('');
             }
            return filtered;
          });
        }
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, [editingTaskId]);

  // Compute task counts per column
  // Compute task counts per column
  const tasksByColumn = useCallback(() => {
    const grouped: { [columnId: string]: typeof tasks } = {};
    const cols = props.columns || [];
    cols.forEach((col) => {
      grouped[col.id || ''] = [];
    });
    tasks.forEach((task) => {
      const col = task.column || '';
      if (!grouped[col]) {
        grouped[col] = [];
      }
      grouped[col].push(task);
    });
    return grouped;
  }, [tasks, props.columns]);

  const tasksGrouped = tasksByColumn();

  // Total and completed counts
  const totalTasks = tasks.length;
  const doneColumnId = (props.columns || [])[2]?.id || 'done';
   const completedTasks = (tasksGrouped[doneColumnId] || []).length;

  // Handle task move
  const handleMoveTask = useCallback(
    (taskId: string, newColumn: string) => {
      setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t)));
      taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
    },
    [taskUpdate]
  );

  // Handle task edit
  const handleSaveEdit = useCallback(
    (taskId: string) => {
      const task = tasks.find((t) => t.id === taskId);
      const col = task?.column || '';
      setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, title: editingTitle } : t)));
      taskUpdate({ action: 'edit', taskId, data: { column: col, title: editingTitle } });
      setEditingTaskId(null);
      setEditingTitle('');
    },
    [editingTitle, tasks, taskUpdate]
  );

  // Handle add task
  // Handle add task
  const handleAddTask = useCallback(
    (columnId: string) => {
      const newId = `task-${Date.now()}`;
      const newTask = {
        id: newId,
        title: newTaskTitle || 'Untitled Task',
        priority: newTaskPriority,
        assignee: '',
        column: columnId,
        dueDate: '',
      };
      setTasks((prev) => [...prev, newTask]);
       taskUpdate({ action: 'create', taskId: newId, data: { column: columnId, title: newTask.title, priority: newTaskPriority } });
      setNewTaskTitle('');
      setNewTaskPriority('medium');
      setAddingColumnId(null);
    },
    [newTaskTitle, newTaskPriority, taskUpdate]
  );

  return {
    taskUpdate,

    tasks,
    tasksGrouped,
    totalTasks,
    completedTasks,
    editingTaskId,
    setEditingTaskId,
    editingTitle,
    setEditingTitle,
    addingColumnId,
    setAddingColumnId,
    newTaskTitle,
    setNewTaskTitle,
    newTaskPriority,
    setNewTaskPriority,
    handleMoveTask,
    handleSaveEdit,
    handleAddTask,
  };
}

export default function Component(props: Props) {
  const state = useComponent(props);

  const priorityColors: { [key: string]: 'success' | 'warning' | 'error' } = {
    low: 'success',
    medium: 'warning',
    high: 'error',
  };

  return (
    <Stack gap={16}>
      {/* Summary bar */}
      <Card shadow="md" padding={16} border>
        <Row align="center" gap={12} justify="between">
          <Stack direction="horizontal" gap={24} align="center">
            <div>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Total Tasks</Text>
              <Text variant="bodyLarge" weight="bold">{state.totalTasks}</Text>
            </div>
            <Divider orientation="vertical" margin={0} />
            <div>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Completed</Text>
              <Text variant="bodyLarge" weight="bold">{state.completedTasks}</Text>
            </div>
          </Stack>
          <Progress value={state.totalTasks > 0 ? (state.completedTasks / state.totalTasks) * 100 : 0} variant="success" size="md" />
        </Row>
      </Card>

      {/* Kanban board */}
      <Row gap={16} align="start" wrap>
        {(props.columns || []).map((column) => {
          const colTasks = state.tasksGrouped[column.id || ''] || [];
          const isAdding = state.addingColumnId === column.id;

          return (
            <Card
              key={column.id}
              padding={12}
              shadow="sm"
              style={{
                flex: '1 1 280px',
                minWidth: '280px',
                maxWidth: '400px',
                display: 'flex',
                flexDirection: 'column',
              }}
            >
              {/* Column header */}
              <Stack gap={12} style={{ marginBottom: 'var(--ggui-spacing-4, 16px)' }}>
                <Row justify="between" align="center">
                  <Heading level={5}>{column.name || 'Unnamed'}</Heading>
                  <Badge variant="primary" size="sm">{colTasks.length}</Badge>
                </Row>
                <Divider margin={0} />
              </Stack>

              {/* Task list */}
              <Stack
                gap={8}
                style={{
                  flex: 1,
                  overflowY: 'auto',
                  paddingRight: 'var(--ggui-spacing-2, 8px)',
                  minHeight: '300px',
                }}
              >
                {colTasks.map((task) => {
                  const isEditing = state.editingTaskId === task.id;
                  const taskPriority = task.priority || 'medium';

                  return (
                    <Card
                      key={task.id}
                      padding={12}
                      shadow="sm"
                      border
                      as={Pressable}
                      onPress={() => {
                        if (!isEditing) {
                          state.setEditingTaskId(task.id || null);
                          state.setEditingTitle(task.title || '');
                        }
                      }}
                      pressStyle={{ transform: 'scale(0.98)', opacity: 0.9 }}
                    >
                      <Stack gap={8}>
                        {/* Title */}
                        {isEditing ? (
                          <Input
                            label="Task title"
                            value={state.editingTitle}
                            onChange={state.setEditingTitle}
                            placeholder="Task title"
                            size="sm"
                          />
                        ) : (
                          <Text variant="body" weight="medium" truncate>
                            {task.title || 'Untitled'}
                          </Text>
                        )}

                        {/* Priority badge */}
                        <Badge variant={priorityColors[taskPriority] || 'default'} size="sm">{taskPriority}</Badge>

                        {/* Assignee and due date */}
                        {task.assignee && (
                          <Avatar name={task.assignee} size="sm" />
                        )}
                        {task.dueDate && (
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{task.dueDate}</Text>
                        )}

                        {/* Actions */}
                        <Row gap={4} justify="end">
                          {isEditing ? (
                            <>
                              <Button
                                size="xs"
                                variant="primary"
                                onClick={(e) => {
                                  e.stopPropagation?.();
                                  state.handleSaveEdit(task.id || '');
                                }}
                              >
                                Save
                              </Button>
                              <Button
                                size="xs"
                                variant="ghost"
                                onClick={(e) => {
                                  e.stopPropagation?.();
                                  state.setEditingTaskId(null);
                                }}
                              >
                                Cancel
                              </Button>
                            </>
                          ) : (
                            <Dropdown
                              trigger={<Icon name="move" size={16} />}
                              options={(props.columns || [])
                                .filter((col) => col.id !== column.id)
                                .map((col) => ({ value: col.id || '', label: `Move to ${col.name}` }))}
                              value=""
                              onChange={(colId) => {
                                state.handleMoveTask(task.id || '', colId);
                              }}
                              placement="bottom-end"
                            />
                          )}
                        </Row>
                      </Stack>
                    </Card>
                  );
                })}
              </Stack>

              {/* Add task button/form */}
              <Stack gap={8} style={{ marginTop: 'var(--ggui-spacing-4, 16px)' }}>
                <Divider margin={0} />
                {isAdding ? (
                  <Stack gap={8}>
                    <Input
                      label="Task title"
                      value={state.newTaskTitle}
                      onChange={state.setNewTaskTitle}
                      placeholder="New task title"
                      size="sm"
                    />
                    <Select
                      label="Priority"
                      value={state.newTaskPriority}
                      onChange={(v) => state.setNewTaskPriority(v as 'low' | 'medium' | 'high')}
                      options={[
                        { value: 'low', label: 'Low' },
                        { value: 'medium', label: 'Medium' },
                        { value: 'high', label: 'High' },
                      ]}
                      size="sm"
                    />
                    <Row gap={4}>
                      <Button
                        size="xs"
                        variant="primary"
                        fullWidth
                        onClick={() => state.handleAddTask(column.id || '')}
                      >
                        Add
                      </Button>
                      <Button
                        size="xs"
                        variant="ghost"
                        fullWidth
                        onClick={() => state.setAddingColumnId(null)}
                      >
                        Cancel
                      </Button>
                    </Row>
                  </Stack>
                ) : (
                  <Button
                    size="sm"
                    variant="outline"
                    fullWidth
                    onClick={() => state.setAddingColumnId(column.id || '')}
                  >
                    + Add Task
                  </Button>
                )}
              </Stack>
            </Card>
          );
        })}
      </Row>
    </Stack>
  );
}
